import json
import re

# Load data
file_path = locals()['var_function-call-10833735353448938107']
with open(file_path, 'r') as f:
    data = json.load(f)

print("Total records:", len(data))

# Check DE filtering
de_count = 0
for p in data[:100]:
    p_info = p.get('Patents_info', '')
    if 'DE-' in p_info or 'Germany' in p_info:
        de_count += 1
print("DE matches in first 100:", de_count)

# Check Date Parsing
def parse_date(date_str):
    if not date_str:
        return None
    s = date_str.lower()
    for w in ["dated", "on", "of", "the", ",", "st", "nd", "rd", "th"]:
        s = s.replace(w, " ")

    y_match = re.search(r'\b(19|20)\d{2}\b', s)
    if not y_match:
        return None
    year = int(y_match.group(0))
    s_no_year = s.replace(str(year), " ")

    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }
    mon = 1
    for m, v in months.items():
        if m in s_no_year:
            mon = v
            break

    return pd.Timestamp(year=year, month=mon, day=1)

h2_count = 0
for p in data:
    g_date = parse_date(p.get('grant_date', ''))
    if g_date and g_date.year == 2019 and g_date.month >= 7:
        h2_count += 1

print("H2 2019 matches:", h2_count)

# Print some samples
print("__RESULT__:")
print(json.dumps([{"p_info": p['Patents_info'], "g_date": p['grant_date']} for p in data[:5]]))"}

{"code":"import pandas as pd
import json
import re

file_path = locals()['var_function-call-10833735353448938107']
with open(file_path, 'r') as f:
    data = json.load(f)

def parse_date(date_str):
    if not date_str:
        return None
    s = date_str.lower()
    for w in ["dated", "on", "of", "the", ",", "st", "nd", "rd", "th"]:
        s = s.replace(w, " ")

    y_match = re.search(r'\b(19|20)\d{2}\b', s)
    if not y_match:
        return None
    year = int(y_match.group(0))

    s_no_year = s.replace(str(year), " ")

    months = {
        'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
        'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
    }
    mon = 1
    found = False
    for m, v in months.items():
        if m in s_no_year:
            mon = v
            found = True
            break

    # If month not found, maybe return None?
    # For H2 check, we need month.
    if not found:
        return None 

    return pd.Timestamp(year=year, month=mon, day=1)

stats = {
    "total": len(data),
    "de_filter": 0,
    "grant_date_parsed": 0,
    "h2_2019": 0,
    "filing_date_parsed": 0,
    "cpc_parsed": 0,
    "rows_generated": 0
}

filtered_rows = []
for p in data:
    p_info = p.get('Patents_info', '')
    if 'DE-' in p_info or 'Germany' in p_info:
        stats["de_filter"] += 1
    else:
        continue

    g_date = parse_date(p.get('grant_date', ''))
    if g_date:
        stats["grant_date_parsed"] += 1
        if g_date.year == 2019 and g_date.month >= 7:
            stats["h2_2019"] += 1
        else:
            continue
    else:
        continue

    f_date = parse_date(p.get('filing_date', ''))
    if f_date:
        stats["filing_date_parsed"] += 1
        filing_year = f_date.year
    else:
        continue

    try:
        cpc_items = json.loads(p.get('cpc', '[]'))
        stats["cpc_parsed"] += 1
    except:
        continue

    for item in cpc_items:
        code = item.get('code', '')
        if '/' in code:
            parts = code.split('/')
            mg = parts[0] + '/00'
            filtered_rows.append({'cpc': mg, 'year': filing_year})
            stats["rows_generated"] += 1

print('__RESULT__:')
print(json.dumps(stats))"}

